arguments.file_text:
@page "/patients"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>Patients</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>Patients</h1>
    <button class="btn btn-primary" @onclick="() => showAddOwner = true">
        <span class="bi bi-plus-circle me-1"></span> New Owner &amp; Pet
    </button>
</div>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search owners or pets..." @bind="searchTerm" @bind:event="oninput" />
</div>

@if (showAddOwner)
{
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between">
            <strong>Register New Owner &amp; Pet</strong>
            <button class="btn-close" @onclick="() => showAddOwner = false"></button>
        </div>
        <div class="card-body">
            <EditForm Model="newOwner" OnValidSubmit="AddOwner" FormName="addOwner">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row mb-2">
                    <div class="col-md-3">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="newOwner.FirstName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="newOwner.LastName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="newOwner.Phone" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="newOwner.Email" />
                    </div>
                </div>
                <hr />
                <h6>First Pet</h6>
                <div class="row mb-2">
                    <div class="col-md-3">
                        <label class="form-label">Pet Name</label>
                        <InputText class="form-control" @bind-Value="newPet.Name" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Species</label>
                        <InputSelect class="form-select" @bind-Value="newPet.Species">
                            <option value="">Select...</option>
                            <option>Dog</option>
                            <option>Cat</option>
                            <option>Bird</option>
                            <option>Rabbit</option>
                            <option>Reptile</option>
                            <option>Other</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="newPet.Breed" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="newPet.WeightKg" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Register</button>
            </EditForm>
        </div>
    </div>
}

@if (owners == null)
{
    <p>Loading...</p>
}
else if (!FilteredOwners.Any())
{
    <p class="text-muted">No patients found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-hover">
            <thead>
                <tr>
                    <th>Owner</th>
                    <th>Phone</th>
                    <th>Email</th>
                    <th>Pets</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var owner in FilteredOwners)
                {
                    <tr>
                        <td>@owner.FullName</td>
                        <td>@owner.Phone</td>
                        <td>@owner.Email</td>
                        <td>
                            @foreach (var pet in owner.Pets)
                            {
                                <a href="/patients/@pet.Id" class="badge bg-info text-decoration-none me-1">
                                    @pet.Name (@pet.Species)
                                </a>
                            }
                        </td>
                        <td>
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => Nav.NavigateTo($&quot;/patients/add-pet/{owner.Id}&quot;)">
                                + Pet
                            </button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<VetClinic.Data.Owner>? owners;
    private string searchTerm = "";
    private bool showAddOwner;
    private VetClinic.Data.Owner newOwner = new();
    private VetClinic.Data.Pet newPet = new();

    private IEnumerable<VetClinic.Data.Owner> FilteredOwners =>
        owners?.Where(o =>
            string.IsNullOrWhiteSpace(searchTerm) ||
            o.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            o.Pets.Any(p => p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
        ) ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        owners = await db.Owners.Include(o => o.Pets).OrderBy(o => o.LastName).ToListAsync();
    }

    private async Task AddOwner()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        newPet.Owner = newOwner;
        newOwner.Pets.Add(newPet);
        db.Owners.Add(newOwner);
        await db.SaveChangesAsync();
        newOwner = new();
        newPet = new();
        showAddOwner = false;
        await LoadData();
    }
}

@page "/patients/add-pet/{OwnerId:int}"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>Add Pet</PageTitle>

<h1>Add Pet</h1>

@if (owner == null)
{
    <p>Loading...</p>
}
else
{
    <p>Adding pet for <strong>@owner.FullName</strong></p>

    <EditForm Model="pet" OnValidSubmit="Save" FormName="addPet">
        <DataAnnotationsValidator />
        <ValidationSummary />
        <div class="row mb-3">
            <div class="col-md-4">
                <label class="form-label">Name</label>
                <InputText class="form-control" @bind-Value="pet.Name" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Species</label>
                <InputSelect class="form-select" @bind-Value="pet.Species">
                    <option value="">Select...</option>
                    <option>Dog</option>
                    <option>Cat</option>
                    <option>Bird</option>
                    <option>Rabbit</option>
                    <option>Reptile</option>
                    <option>Other</option>
                </InputSelect>
            </div>
            <div class="col-md-4">
                <label class="form-label">Breed</label>
                <InputText class="form-control" @bind-Value="pet.Breed" />
            </div>
        </div>
        <div class="row mb-3">
            <div class="col-md-4">
                <label class="form-label">Date of Birth</label>
                <InputDate class="form-control" @bind-Value="pet.DateOfBirth" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Weight (kg)</label>
                <InputNumber class="form-control" @bind-Value="pet.WeightKg" />
            </div>
        </div>
        <button type="submit" class="btn btn-success">Save</button>
        <button type="button" class="btn btn-secondary ms-2" @onclick='() => Nav.NavigateTo("/patients")'>Cancel</button>
    </EditForm>
}

@code {
    [Parameter] public int OwnerId { get; set; }

    private VetClinic.Data.Owner? owner;
    private VetClinic.Data.Pet pet = new();

    protected override async Task OnInitializedAsync()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        owner = await db.Owners.FindAsync(OwnerId);
    }

    private async Task Save()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        pet.OwnerId = OwnerId;
        db.Pets.Add(pet);
        await db.SaveChangesAsync();
        Nav.NavigateTo("/patients");
    }
}

@page "/patients/{PetId:int}"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>Patient Details</PageTitle>

@if (pet == null)
{
    <p>Loading...</p>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h1>@pet.Name</h1>
        <button class="btn btn-outline-secondary" @onclick='() => Nav.NavigateTo("/patients")'>← Back</button>
    </div>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="card">
                <div class="card-header d-flex justify-content-between">
                    <strong>Pet Information</strong>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => editingPet = !editingPet">
                        @(editingPet ? "Cancel" : "Edit")
                    </button>
                </div>
                <div class="card-body">
                    @if (editingPet)
                    {
                        <EditForm Model="pet" OnValidSubmit="SavePet" FormName="editPet">
                            <DataAnnotationsValidator />
                            <div class="mb-2">
                                <label class="form-label">Name</label>
                                <InputText class="form-control" @bind-Value="pet.Name" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Species</label>
                                <InputSelect class="form-select" @bind-Value="pet.Species">
                                    <option>Dog</option>
                                    <option>Cat</option>
                                    <option>Bird</option>
                                    <option>Rabbit</option>
                                    <option>Reptile</option>
                                    <option>Other</option>
                                </InputSelect>
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Breed</label>
                                <InputText class="form-control" @bind-Value="pet.Breed" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Date of Birth</label>
                                <InputDate class="form-control" @bind-Value="pet.DateOfBirth" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Weight (kg)</label>
                                <InputNumber class="form-control" @bind-Value="pet.WeightKg" />
                            </div>
                            <button type="submit" class="btn btn-success btn-sm">Save</button>
                        </EditForm>
                    }
                    else
                    {
                        <dl class="row mb-0">
                            <dt class="col-sm-4">Species</dt>
                            <dd class="col-sm-8">@pet.Species</dd>
                            <dt class="col-sm-4">Breed</dt>
                            <dd class="col-sm-8">@(pet.Breed ?? "—")</dd>
                            <dt class="col-sm-4">Date of Birth</dt>
                            <dd class="col-sm-8">@(pet.DateOfBirth?.ToString("yyyy-MM-dd") ?? "—")</dd>
                            <dt class="col-sm-4">Weight</dt>
                            <dd class="col-sm-8">@(pet.WeightKg.HasValue ? $"{pet.WeightKg} kg" : "—")</dd>
                            <dt class="col-sm-4">Owner</dt>
                            <dd class="col-sm-8">@pet.Owner.FullName — @pet.Owner.Phone</dd>
                        </dl>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between">
            <strong>Medical History / Treatment Notes</strong>
            <button class="btn btn-sm btn-primary" @onclick="() => showAddNote = !showAddNote">+ Add Note</button>
        </div>
        <div class="card-body">
            @if (showAddNote)
            {
                <EditForm Model="newNote" OnValidSubmit="AddNote" FormName="addNote" class="mb-3 p-3 bg-light rounded">
                    <DataAnnotationsValidator />
                    <ValidationSummary />
                    <div class="row mb-2">
                        <div class="col-md-4">
                            <label class="form-label">Veterinarian</label>
                            <InputText class="form-control" @bind-Value="newNote.Veterinarian" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Date</label>
                            <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="newNote.Date" />
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Description</label>
                        <InputTextArea class="form-control" rows="3" @bind-Value="newNote.Description" />
                    </div>
                    <button type="submit" class="btn btn-success btn-sm">Save Note</button>
                </EditForm>
            }

            @if (!pet.TreatmentNotes.Any())
            {
                <p class="text-muted mb-0">No treatment notes yet.</p>
            }
            else
            {
                <div class="table-responsive">
                    <table class="table table-sm">
                        <thead>
                            <tr>
                                <th>Date</th>
                                <th>Veterinarian</th>
                                <th>Description</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var note in pet.TreatmentNotes.OrderByDescending(n => n.Date))
                            {
                                <tr>
                                    <td>@note.Date.ToString("g")</td>
                                    <td>@note.Veterinarian</td>
                                    <td>@note.Description</td>
                                    <td>
                                        <button class="btn btn-sm btn-outline-danger" @onclick="() => DeleteNote(note.Id)">Delete</button>
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
        </div>
    </div>

    <div class="card">
        <div class="card-header"><strong>Appointment History</strong></div>
        <div class="card-body">
            @if (!pet.Appointments.Any())
            {
                <p class="text-muted mb-0">No appointments yet.</p>
            }
            else
            {
                <div class="table-responsive">
                    <table class="table table-sm">
                        <thead>
                            <tr>
                                <th>Date/Time</th>
                                <th>Duration</th>
                                <th>Reason</th>
                                <th>Status</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var appt in pet.Appointments.OrderByDescending(a => a.StartTime))
                            {
                                <tr>
                                    <td>@appt.StartTime.ToString("g")</td>
                                    <td>@appt.DurationMinutes min</td>
                                    <td>@appt.Reason</td>
                                    <td>
                                        <span class="badge @(appt.Status == VetClinic.Data.AppointmentStatus.Scheduled ? "bg-primary" : appt.Status == VetClinic.Data.AppointmentStatus.Completed ? "bg-success" : "bg-secondary")">
                                            @appt.Status
                                        </span>
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter] public int PetId { get; set; }

    private VetClinic.Data.Pet? pet;
    private bool editingPet;
    private bool showAddNote;
    private VetClinic.Data.TreatmentNote newNote = new() { Date = DateTime.Now };

    protected override async Task OnInitializedAsync()
    {
        await LoadPet();
    }

    private async Task LoadPet()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        pet = await db.Pets
            .Include(p => p.Owner)
            .Include(p => p.TreatmentNotes)
            .Include(p => p.Appointments)
            .FirstOrDefaultAsync(p => p.Id == PetId);
    }

    private async Task SavePet()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        db.Pets.Update(pet!);
        await db.SaveChangesAsync();
        editingPet = false;
    }

    private async Task AddNote()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        newNote.PetId = PetId;
        db.TreatmentNotes.Add(newNote);
        await db.SaveChangesAsync();
        newNote = new() { Date = DateTime.Now };
        showAddNote = false;
        await LoadPet();
    }

    private async Task DeleteNote(int noteId)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var note = await db.TreatmentNotes.FindAsync(noteId);
        if (note != null)
        {
            db.TreatmentNotes.Remove(note);
            await db.SaveChangesAsync();
        }
        await LoadPet();
    }
}

@page "/appointments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory

<PageTitle>Appointments</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>Appointments</h1>
    <button class="btn btn-primary" @onclick="() => showNewForm = true">+ New Appointment</button>
</div>

<div class="d-flex align-items-center mb-3 gap-2">
    <button class="btn btn-outline-secondary btn-sm" @onclick="PrevWeek">← Prev</button>
    <strong>@weekStart.ToString("MMM dd") — @weekStart.AddDays(6).ToString("MMM dd, yyyy")</strong>
    <button class="btn btn-outline-secondary btn-sm" @onclick="NextWeek">Next →</button>
    <button class="btn btn-outline-primary btn-sm ms-2" @onclick="GoToday">Today</button>
</div>

@if (showNewForm)
{
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between">
            <strong>@(editingAppointment?.Id > 0 ? "Reschedule Appointment" : "New Appointment")</strong>
            <button class="btn-close" @onclick="CancelForm"></button>
        </div>
        <div class="card-body">
            <EditForm Model="editingAppointment!" OnValidSubmit="SaveAppointment" FormName="newAppt">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Patient</label>
                        <InputSelect class="form-select" @bind-Value="editingAppointment!.PetId">
                            <option value="0">Select patient...</option>
                            @if (pets != null)
                            {
                                @foreach (var p in pets)
                                {
                                    <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                                }
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Date &amp; Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment!.StartTime" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Duration (min)</label>
                        <InputNumber class="form-control" @bind-Value="editingAppointment!.DurationMinutes" />
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Reason</label>
                    <InputText class="form-control" @bind-Value="editingAppointment!.Reason" />
                </div>
                @if (conflictWarning != null)
                {
                    <div class="alert alert-warning py-1">@conflictWarning</div>
                }
                <button type="submit" class="btn btn-success">Save</button>
            </EditForm>
        </div>
    </div>
}

<div class="table-responsive">
    <table class="table table-bordered">
        <thead class="table-light">
            <tr>
                <th style="width:80px">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="text-center @(day.Date == DateTime.Today ? "table-primary" : "")">
                        @day.ToString("ddd MM/dd")
                    </th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour <= 18; hour++)
            {
                <tr>
                    <td class="text-muted small">@($"{hour:D2}:00")</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var slotDate = weekStart.AddDays(d);
                        var slotStart = slotDate.AddHours(hour);
                        var slotEnd = slotStart.AddHours(1);
                        var slotAppts = appointments?.Where(a =>
                            a.Status != VetClinic.Data.AppointmentStatus.Cancelled &&
                            a.StartTime < slotEnd && a.StartTime.AddMinutes(a.DurationMinutes) > slotStart
                        ).ToList() ?? [];

                        <td class="@(slotAppts.Any() ? "" : "table-success")" style="font-size:0.85em; vertical-align:top;">
                            @if (!slotAppts.Any())
                            {
                                <span class="text-muted">Available</span>
                            }
                            @foreach (var a in slotAppts)
                            {
                                <div class="mb-1 p-1 border rounded bg-white">
                                    <strong>@a.StartTime.ToString("HH:mm")</strong> @a.Pet.Name<br />
                                    <small class="text-muted">@a.Reason</small><br />
                                    <span class="badge @StatusBadge(a.Status)">@a.Status</span>
                                    @if (a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
                                    {
                                        <button class="btn btn-outline-primary btn-sm py-0 px-1 ms-1" @onclick="() => Reschedule(a)">Reschedule</button>
                                        <button class="btn btn-outline-success btn-sm py-0 px-1" @onclick="() => Complete(a.Id)">Complete</button>
                                        <button class="btn btn-outline-danger btn-sm py-0 px-1" @onclick="() => Cancel(a.Id)">Cancel</button>
                                    }
                                </div>
                            }
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private List<VetClinic.Data.Appointment>? appointments;
    private List<VetClinic.Data.Pet>? pets;
    private DateTime weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek + (int)DayOfWeek.Monday);
    private bool showNewForm;
    private VetClinic.Data.Appointment? editingAppointment;
    private string? conflictWarning;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var weekEnd = weekStart.AddDays(7);
        appointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private void PrevWeek() { weekStart = weekStart.AddDays(-7); _ = LoadData(); }
    private void NextWeek() { weekStart = weekStart.AddDays(7); _ = LoadData(); }
    private void GoToday() { weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek + (int)DayOfWeek.Monday); _ = LoadData(); }

    private void CancelForm()
    {
        showNewForm = false;
        editingAppointment = null;
        conflictWarning = null;
    }

    private async Task SaveAppointment()
    {
        if (editingAppointment == null || editingAppointment.PetId == 0) return;

        using var db = await DbFactory.CreateDbContextAsync();

        var apptEnd = editingAppointment.StartTime.AddMinutes(editingAppointment.DurationMinutes);
        var conflict = await db.Appointments.AnyAsync(a =>
            a.Id != editingAppointment.Id &&
            a.Status == VetClinic.Data.AppointmentStatus.Scheduled &&
            a.StartTime < apptEnd &&
            a.StartTime.AddMinutes(a.DurationMinutes) > editingAppointment.StartTime);

        if (conflict)
        {
            conflictWarning = "This time slot overlaps with another appointment.";
            return;
        }

        if (editingAppointment.Id > 0)
        {
            db.Appointments.Update(editingAppointment);
        }
        else
        {
            db.Appointments.Add(editingAppointment);
        }
        await db.SaveChangesAsync();
        CancelForm();
        await LoadData();
    }

    private void Reschedule(VetClinic.Data.Appointment appt)
    {
        editingAppointment = appt;
        showNewForm = true;
    }

    private async Task Complete(int id)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var appt = await db.Appointments.FindAsync(id);
        if (appt != null) { appt.Status = VetClinic.Data.AppointmentStatus.Completed; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private async Task Cancel(int id)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var appt = await db.Appointments.FindAsync(id);
        if (appt != null) { appt.Status = VetClinic.Data.AppointmentStatus.Cancelled; await db.SaveChangesAsync(); }
        await LoadData();
    }

    private static string StatusBadge(VetClinic.Data.AppointmentStatus s) => s switch
    {
        VetClinic.Data.AppointmentStatus.Scheduled => "bg-primary",
        VetClinic.Data.AppointmentStatus.Completed => "bg-success",
        VetClinic.Data.AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}

