@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory

<PageTitle>Billing</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>Billing</h1>
    <button class="btn btn-primary" @onclick="() => showNewInvoice = true">+ New Invoice</button>
</div>

@if (showNewInvoice)
{
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between">
            <strong>Create Invoice</strong>
            <button class="btn-close" @onclick="() => { showNewInvoice = false; selectedAppointmentId = 0; }"></button>
        </div>
        <div class="card-body">
            <div class="mb-2">
                <label class="form-label">Completed Appointment (without invoice)</label>
                <select class="form-select" @bind="selectedAppointmentId">
                    <option value="0">Select...</option>
                    @if (unbilledAppointments != null)
                    {
                        @foreach (var a in unbilledAppointments)
                        {
                            <option value="@a.Id">@a.StartTime.ToString("g") — @a.Pet.Name (@a.Pet.Owner.FullName) — @a.Reason</option>
                        }
                    }
                </select>
            </div>
            <button class="btn btn-success" @onclick="CreateInvoice" disabled="@(selectedAppointmentId == 0)">Create Invoice</button>
        </div>
    </div>
}

@if (invoices == null)
{
    <p>Loading...</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-hover">
            <thead>
                <tr>
                    <th>Invoice #</th>
                    <th>Date</th>
                    <th>Patient</th>
                    <th>Owner</th>
                    <th>Total</th>
                    <th>Paid</th>
                    <th>Balance</th>
                    <th>Status</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var inv in invoices)
                {
                    <tr>
                        <td>INV-@inv.Id.ToString("D5")</td>
                        <td>@inv.Date.ToString("d")</td>
                        <td>@inv.Appointment.Pet.Name</td>
                        <td>@inv.Appointment.Pet.Owner.FullName</td>
                        <td>@inv.Total.ToString("C")</td>
                        <td>@inv.AmountPaid.ToString("C")</td>
                        <td class="@(inv.Balance > 0 ? "text-danger fw-bold" : "text-success")">@inv.Balance.ToString("C")</td>
                        <td><span class="badge @InvoiceBadge(inv.Status)">@inv.Status</span></td>
                        <td>
                            <button class="btn btn-sm btn-outline-primary" @onclick="() => SelectInvoice(inv.Id)">Manage</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (selectedInvoice != null)
{
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between">
            <strong>INV-@selectedInvoice.Id.ToString("D5") — @selectedInvoice.Appointment.Pet.Name</strong>
            <button class="btn-close" @onclick="() => selectedInvoice = null"></button>
        </div>
        <div class="card-body">
            <h6>Line Items</h6>
            <table class="table table-sm">
                <thead><tr><th>Description</th><th class="text-end">Amount</th><th></th></tr></thead>
                <tbody>
                    @foreach (var li in selectedInvoice.LineItems)
                    {
                        <tr>
                            <td>@li.Description</td>
                            <td class="text-end">@li.Amount.ToString("C")</td>
                            <td>
                                <button class="btn btn-sm btn-outline-danger py-0" @onclick="() => RemoveLineItem(li.Id)">×</button>
                            </td>
                        </tr>
                    }
                    <tr>
                        <td>
                            <input class="form-control form-control-sm" placeholder="Description" @bind="newLineDesc" />
                        </td>
                        <td>
                            <input type="number" step="0.01" class="form-control form-control-sm text-end" @bind="newLineAmount" />
                        </td>
                        <td>
                            <button class="btn btn-sm btn-success py-0" @onclick="AddLineItem">+</button>
                        </td>
                    </tr>
                    <tr class="table-light fw-bold">
                        <td>Total</td>
                        <td class="text-end">@selectedInvoice.Total.ToString("C")</td>
                        <td></td>
                    </tr>
                </tbody>
            </table>

            @if (selectedInvoice.Status == VetClinic.Data.InvoiceStatus.Draft)
            {
                <button class="btn btn-primary btn-sm mb-3" @onclick="IssueInvoice">Issue Invoice</button>
            }

            <h6>Payments</h6>
            <table class="table table-sm">
                <thead><tr><th>Date</th><th>Method</th><th class="text-end">Amount</th></tr></thead>
                <tbody>
                    @foreach (var p in selectedInvoice.Payments)
                    {
                        <tr>
                            <td>@p.Date.ToString("g")</td>
                            <td>@p.Method</td>
                            <td class="text-end">@p.Amount.ToString("C")</td>
                        </tr>
                    }
                </tbody>
            </table>

            @if (selectedInvoice.Balance > 0 && selectedInvoice.Status != VetClinic.Data.InvoiceStatus.Draft)
            {
                <div class="row g-2 align-items-end">
                    <div class="col-auto">
                        <label class="form-label">Amount</label>
                        <input type="number" step="0.01" class="form-control form-control-sm" @bind="paymentAmount" />
                    </div>
                    <div class="col-auto">
                        <label class="form-label">Method</label>
                        <select class="form-select form-select-sm" @bind="paymentMethod">
                            @foreach (var m in Enum.GetValues<VetClinic.Data.PaymentMethod>())
                            {
                                <option value="@m">@m</option>
                            }
                        </select>
                    </div>
                    <div class="col-auto">
                        <button class="btn btn-success btn-sm" @onclick="RecordPayment">Record Payment</button>
                    </div>
                </div>
            }
        </div>
    </div>
}

@code {
    private List<VetClinic.Data.Invoice>? invoices;
    private List<VetClinic.Data.Appointment>? unbilledAppointments;
    private VetClinic.Data.Invoice? selectedInvoice;
    private bool showNewInvoice;
    private int selectedAppointmentId;

    private string newLineDesc = "";
    private decimal newLineAmount;
    private decimal paymentAmount;
    private VetClinic.Data.PaymentMethod paymentMethod;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        invoices = await db.Invoices
            .Include(i => i.Appointment).ThenInclude(a => a.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.Date)
            .ToListAsync();

        unbilledAppointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.Status == VetClinic.Data.AppointmentStatus.Completed && a.Invoice == null)
            .OrderByDescending(a => a.StartTime)
            .ToListAsync();
    }

    private async Task CreateInvoice()
    {
        if (selectedAppointmentId == 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var inv = new VetClinic.Data.Invoice { AppointmentId = selectedAppointmentId, Date = DateTime.Now };
        db.Invoices.Add(inv);
        await db.SaveChangesAsync();
        showNewInvoice = false;
        selectedAppointmentId = 0;
        await LoadData();
        SelectInvoice(inv.Id);
    }

    private void SelectInvoice(int id)
    {
        selectedInvoice = invoices?.FirstOrDefault(i => i.Id == id);
    }

    private async Task AddLineItem()
    {
        if (selectedInvoice == null || string.IsNullOrWhiteSpace(newLineDesc)) return;
        using var db = await DbFactory.CreateDbContextAsync();
        db.InvoiceLineItems.Add(new VetClinic.Data.InvoiceLineItem
        {
            InvoiceId = selectedInvoice.Id,
            Description = newLineDesc,
            Amount = newLineAmount
        });
        await db.SaveChangesAsync();
        newLineDesc = "";
        newLineAmount = 0;
        await LoadData();
        SelectInvoice(selectedInvoice.Id);
    }

    private async Task RemoveLineItem(int id)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var li = await db.InvoiceLineItems.FindAsync(id);
        if (li != null) { db.InvoiceLineItems.Remove(li); await db.SaveChangesAsync(); }
        var invId = selectedInvoice!.Id;
        await LoadData();
        SelectInvoice(invId);
    }

    private async Task IssueInvoice()
    {
        if (selectedInvoice == null) return;
        using var db = await DbFactory.CreateDbContextAsync();
        var inv = await db.Invoices.FindAsync(selectedInvoice.Id);
        if (inv != null) { inv.Status = VetClinic.Data.InvoiceStatus.Issued; await db.SaveChangesAsync(); }
        var invId = selectedInvoice.Id;
        await LoadData();
        SelectInvoice(invId);
    }

    private async Task RecordPayment()
    {
        if (selectedInvoice == null || paymentAmount <= 0) return;
        using var db = await DbFactory.CreateDbContextAsync();
        db.Payments.Add(new VetClinic.Data.Payment
        {
            InvoiceId = selectedInvoice.Id,
            Amount = paymentAmount,
            Method = paymentMethod,
            Date = DateTime.Now
        });

        var inv = await db.Invoices.Include(i => i.Payments).Include(i => i.LineItems).FirstAsync(i => i.Id == selectedInvoice.Id);
        var totalPaid = inv.Payments.Sum(p => p.Amount) + paymentAmount;
        var total = inv.LineItems.Sum(li => li.Amount);
        inv.Status = totalPaid >= total ? VetClinic.Data.InvoiceStatus.Paid : VetClinic.Data.InvoiceStatus.PartiallyPaid;

        await db.SaveChangesAsync();
        paymentAmount = 0;
        var invId = selectedInvoice.Id;
        await LoadData();
        SelectInvoice(invId);
    }

    private static string InvoiceBadge(VetClinic.Data.InvoiceStatus s) => s switch
    {
        VetClinic.Data.InvoiceStatus.Draft => "bg-secondary",
        VetClinic.Data.InvoiceStatus.Issued => "bg-primary",
        VetClinic.Data.InvoiceStatus.Paid => "bg-success",
        VetClinic.Data.InvoiceStatus.PartiallyPaid => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}
