    private bool showAddOwner;
    private VetClinic.Data.Owner newOwner = new();
    private VetClinic.Data.Pet newPet = new();

    private IEnumerable<VetClinic.Data.Owner> FilteredOwners =>
        owners?.Where(o =>
            string.IsNullOrWhiteSpace(searchTerm) ||
            o.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            o.Pets.Any(p => p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
        ) ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        owners = await db.Owners.Include(o => o.Pets).OrderBy(o => o.LastName).ToListAsync();
    }

    private async Task AddOwner()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        newPet.Owner = newOwner;
        newOwner.Pets.Add(newPet);
        db.Owners.Add(newOwner);
        await db.SaveChangesAsync();
        newOwner = new();
        newPet = new();
        showAddOwner = false;
        await LoadData();
    }
}

