                                <th>Date</th>
                                <th>Veterinarian</th>
                                <th>Description</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var note in pet.TreatmentNotes.OrderByDescending(n => n.Date))
                            {
                                <tr>
                                    <td>@note.Date.ToString("g")</td>
                                    <td>@note.Veterinarian</td>
                                    <td>@note.Description</td>
                                    <td>
                                        <button class="btn btn-sm btn-outline-danger" @onclick="() => DeleteNote(note.Id)">Delete</button>
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
        </div>
