@page "/"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<VetClinic.Data.ApplicationDbContext> DbFactory

<PageTitle>VetClinic Dashboard</PageTitle>

<h1 class="mb-4">🐾 VetClinic Dashboard</h1>

<div class="row g-4 mb-4">
    <div class="col-md-3">
        <div class="card text-bg-primary">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
                <a href="/patients" class="btn btn-light btn-sm">Manage →</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayApptCount</p>
                <a href="/appointments" class="btn btn-light btn-sm">View Calendar →</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning">
            <div class="card-body">
                <h5 class="card-title">Unpaid Invoices</h5>
                <p class="card-text display-6">@unpaidCount</p>
                <a href="/billing" class="btn btn-light btn-sm">Billing →</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
            </div>
        </div>
    </div>
</div>

<h4>Upcoming Appointments</h4>
@if (upcoming == null || !upcoming.Any())
{
    <p class="text-muted">No upcoming appointments.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-hover">
            <thead><tr><th>Time</th><th>Patient</th><th>Owner</th><th>Reason</th></tr></thead>
            <tbody>
                @foreach (var a in upcoming)
                {
                    <tr>
                        <td>@a.StartTime.ToString("g")</td>
                        <td><a href="/patients/@a.PetId">@a.Pet.Name</a></td>
                        <td>@a.Pet.Owner.FullName</td>
                        <td>@a.Reason</td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private int petCount, todayApptCount, unpaidCount, ownerCount;
    private List<VetClinic.Data.Appointment>? upcoming;

    protected override async Task OnInitializedAsync()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        petCount = await db.Pets.CountAsync();
        ownerCount = await db.Owners.CountAsync();

        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);
        todayApptCount = await db.Appointments.CountAsync(a =>
            a.StartTime >= today && a.StartTime < tomorrow &&
            a.Status == VetClinic.Data.AppointmentStatus.Scheduled);

        unpaidCount = await db.Invoices.CountAsync(i =>
            i.Status == VetClinic.Data.InvoiceStatus.Issued ||
            i.Status == VetClinic.Data.InvoiceStatus.PartiallyPaid);

        upcoming = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= DateTime.Now && a.Status == VetClinic.Data.AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(10)
            .ToListAsync();
    }
}

